insert into daily_questions (id, text, category, depth_level, long_distance_suitable, active)
values
  ('00000000-0000-0000-0000-000000000114', 'Welche kleine Geste von mir bleibt dir laenger im Herzen?', 'romance', 1, true, true),
  ('00000000-0000-0000-0000-000000000115', 'Was hat dich diese Woche zum Schmunzeln gebracht?', 'humor', 1, true, true),
  ('00000000-0000-0000-0000-000000000116', 'Welcher gemeinsame Moment hat sich zuletzt leicht angefuehlt?', 'connection', 1, true, true),
  ('00000000-0000-0000-0000-000000000117', 'Wofuer moechtest du mir heute Danke sagen?', 'gratitude', 1, true, true),
  ('00000000-0000-0000-0000-000000000118', 'Welche kleine Sache koennte unseren Alltag gerade schoener machen?', 'everyday', 2, false, true),
  ('00000000-0000-0000-0000-000000000119', 'Was wuenschst du dir fuer unser naechstes ruhiges Gespraech?', 'deep', 3, true, true),
  ('00000000-0000-0000-0000-000000000120', 'Wann fuehlst du dich mir auch aus der Ferne nah?', 'long_distance', 2, true, true),
