  ('00000000-0000-0000-0000-000000000124', 'Was sollten wir bald wieder nur fuer uns machen?', 'date', 1, false, true),
  ('00000000-0000-0000-0000-000000000125', 'Welche liebevolle Nachricht haettest du heute gern gehoert?', 'romance', 2, true, true),
  ('00000000-0000-0000-0000-000000000126', 'Was war ein kleiner Moment, in dem du dich verstanden gefuehlt hast?', 'trust', 2, true, true),
