  ('00000000-0000-0000-0000-000000000128', 'Was koennte ich tun, damit dein Tag morgen leichter wird?', 'support', 2, true, true),
  ('00000000-0000-0000-0000-000000000129', 'Welcher Zukunftsgedanke mit uns fuehlt sich warm an?', 'future', 3, true, true),
  ('00000000-0000-0000-0000-000000000130', 'Welche Grenze oder Pause wuerde dir gerade guttun?', 'deep', 3, true, true),
  ('00000000-0000-0000-0000-000000000131', 'Welche gemeinsame Staerke vergessen wir manchmal?', 'teamwork', 2, true, true),
  ('00000000-0000-0000-0000-000000000132', 'Was moechtest du an unserem Zuhause oder Alltag feiern?', 'everyday', 1, false, true),
  ('00000000-0000-0000-0000-000000000133', 'Welche Sache an mir macht dich stolz?', 'gratitude', 2, true, true),
  ('00000000-0000-0000-0000-000000000134', 'Was waere ein schoenes Mini-Date fuer die naechsten Tage?', 'date', 1, true, true),
  ('00000000-0000-0000-0000-000000000135', 'Welche Sehnsucht moechtest du mir sanft erklaeren?', 'long_distance', 3, true, true),
  ('00000000-0000-0000-0000-000000000136', 'Welche Erinnerung zeigt gut, wer wir als Paar sind?', 'memory', 2, true, true),
  ('00000000-0000-0000-0000-000000000137', 'Wobei fuehlst du dich von mir am besten unterstuetzt?', 'support', 2, true, true),
  ('00000000-0000-0000-0000-000000000138', 'Welche kleine Tradition passt zu unserer aktuellen Lebensphase?', 'ritual', 2, true, true),
  ('00000000-0000-0000-0000-000000000139', 'Was sollten wir uns gegenseitig oefter erlauben?', 'deep', 3, true, true),
