insert into quests (id, title, description, category, estimated_minutes, effort_level, reward_points, reward_seed_type, requires_both_partners)
values
  ('00000000-0000-0000-0000-000000000212', 'Zwei-Minuten-Danke', 'Sagt euch nacheinander eine konkrete Sache, fuer die ihr heute dankbar seid.', 'romance', 2, 'low', 8, 'compliment_seed', true),
  ('00000000-0000-0000-0000-000000000213', 'Lieblingssnack-Date', 'Besorgt oder bereitet einen Lieblingssnack und schenkt euch 15 Minuten ohne Ablenkung.', 'date', 15, 'low', 12, 'date_seed', true),
  ('00000000-0000-0000-0000-000000000214', 'Insider-Wort', 'Erfindet ein neues Wort fuer etwas, das nur ihr beide versteht.', 'humor', 5, 'low', 8, 'humor_seed', true),
  ('00000000-0000-0000-0000-000000000215', 'Foto-Rueckblick', 'Waehlt ein altes Foto aus und erzaehlt euch, was ihr daran moegt.', 'memory', 10, 'low', 12, 'memory_seed', true),
  ('00000000-0000-0000-0000-000000000216', 'Kleine Hilfe', 'Uebernehmt eine kleine Aufgabe, die dem anderen heute Luft gibt.', 'teamwork', 10, 'low', 10, 'support_seed', false),
  ('00000000-0000-0000-0000-000000000217', 'Gleiches Lied', 'Hoert zur gleichen Zeit denselben Song und schreibt euch danach einen Satz.', 'long_distance', 5, 'low', 10, 'light_seed', false),
  ('00000000-0000-0000-0000-000000000218', 'Zukunftszettel', 'Schreibt beide einen Wunsch fuer dieses Jahr auf und lest ihn euch vor.', 'memory', 10, 'low', 12, 'future_seed', true),
  ('00000000-0000-0000-0000-000000000219', 'Spaziergang mit Frage', 'Geht spazieren und nehmt eine Frage mit, die nicht organisatorisch ist.', 'date', 30, 'medium', 20, 'date_seed', true),
  ('00000000-0000-0000-0000-000000000220', 'Stress-Ampel', 'Nennt rot, gelb und gruen fuer eure aktuelle Woche: schwer, mittel, gut.', 'teamwork', 15, 'medium', 18, 'support_seed', true),
  ('00000000-0000-0000-0000-000000000221', 'Kompliment per Sprachnachricht', 'Schickt eine kurze Sprachnachricht mit einem ehrlichen Kompliment.', 'long_distance', 5, 'low', 10, 'compliment_seed', false),
  ('00000000-0000-0000-0000-000000000222', 'Wohnzimmer-Picknick', 'Legt eine Decke aus und macht aus einem normalen Essen ein kleines Picknick.', 'date', 25, 'medium', 18, 'date_seed', true),
  ('00000000-0000-0000-0000-000000000223', 'Drei gute Dinge', 'Nennt drei Dinge, die in eurer Beziehung gerade gut laufen.', 'romance', 10, 'low', 12, 'trust_seed', true),
  ('00000000-0000-0000-0000-000000000224', 'Albernes Selfie', 'Macht ein absichtlich albernes Paar-Selfie oder beschreibt eins aus der Ferne.', 'humor', 5, 'low', 8, 'humor_seed', false),
  ('00000000-0000-0000-0000-000000000225', 'Naechstes Wiedersehen', 'Plant einen kleinen konkreten Punkt fuer euer naechstes Wiedersehen.', 'long_distance', 15, 'medium', 18, 'date_seed', true),
  ('00000000-0000-0000-0000-000000000226', 'Dank an frueher', 'Erinnert euch an eine schwere Phase und sagt, was ihr daran geschafft habt.', 'memory', 20, 'medium', 20, 'memory_seed', true),
  ('00000000-0000-0000-0000-000000000227', 'Mini-Aufraeum-Team', 'Macht gemeinsam einen 10-Minuten-Aufraeum-Sprint mit Musik.', 'teamwork', 10, 'low', 10, 'team_seed', true),
  ('00000000-0000-0000-0000-000000000228', 'Ueberraschung unter 5 Euro', 'Plant eine kleine Ueberraschung, die nicht teuer sein muss.', 'romance', 20, 'medium', 18, 'compliment_seed', false),
  ('00000000-0000-0000-0000-000000000229', 'Sternstunden-Liste', 'Schreibt drei Momente auf, die sich nach euch anfuehlen.', 'memory', 15, 'low', 15, 'memory_seed', true),
  ('00000000-0000-0000-0000-000000000230', 'Keine-Handy-Insel', 'Legt fuer 30 Minuten beide Handys weg und macht etwas Einfaches zusammen.', 'date', 30, 'medium', 20, 'date_seed', true),
  ('00000000-0000-0000-0000-000000000231', 'Wer wuerde eher', 'Spielt zehn schnelle Wer-wuerde-eher-Fragen, liebevoll und ohne Sticheln.', 'humor', 10, 'low', 10, 'humor_seed', true)
